before_code:
module alu_32bit (
  input [31:0] operand_a,
  input [31:0] operand_b,
  input [3:0] opcode,
  output [31:0] alu_result,
  output overflow_flag
);
  always @(*) begin
    case(opcode)
      4'b0000: alu_result = operand_a + operand_b;
      4'b0001: alu_result = operand_a - operand_b;
      4'b0010: alu_result = operand_a & operand_b;
      default: alu_result = 0;
    endcase
  end
endmodule

module alu_top (
  input [31:0] op_a,
  input [31:0] op_b,
  input [3:0] operation,
  output [31:0] result,
  output overflow
);
  alu_32bit alu_inst (
    .operand_a(op_a),
    .operand_b(op_b),
    .alu_result(result),
    .opcode(operation),
    .alu_overflow(overflow)
  );
endmodule

